import requests

BASE = "https://graph.microsoft.com/v1.0"
HDR  = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}

def disable_user(user_id: str) -> None:
    requests.patch(f"{BASE}/users/{user_id}", headers=HDR, json={"accountEnabled": False})
    # Also revoke all active sessions immediately
    requests.post(f"{BASE}/users/{user_id}/revokeSignInSessions", headers=HDR)

def delete_user(user_id: str) -> None:
    requests.delete(f"{BASE}/users/{user_id}", headers=HDR)
    # User moves to deletedItems — restorable for 30 days

def restore_user(user_id: str) -> dict:
    r = requests.post(f"{BASE}/directory/deletedItems/{user_id}/restore", headers=HDR)
    return r.json()

def list_deleted_users() -> list:
    r = requests.get(f"{BASE}/directory/deletedItems/microsoft.graph.user", headers=HDR,
                     params={"$select": "displayName,userPrincipalName,deletedDateTime"})
    return r.json().get("value", [])

# Example: leaver workflow
USER_ID = "xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
disable_user(USER_ID)   # immediate effect — cannot sign in
# ... wait 30 days for data retention ...
delete_user(USER_ID)    # moves to recycle bin

deleted = list_deleted_users()
print(f"{len(deleted)} users in recycle bin:")
for u in deleted:
    print(f"  {u['userPrincipalName']:<50} deleted: {u.get('deletedDateTime','')[:10]}")

import requests
from datetime import datetime, timedelta, timezone

def find_stale_users(token: str, days: int = 90) -> list:
    cutoff = (datetime.now(timezone.utc) - timedelta(days=days)).strftime("%Y-%m-%dT%H:%M:%SZ")
    headers = {"Authorization": f"Bearer {token}"}

    # Requires AuditLog.Read.All permission to read signInActivity
    url = "https://graph.microsoft.com/v1.0/users"
    params = {
        "$select": "id,displayName,userPrincipalName,accountEnabled,signInActivity,userType",
        "$filter": "accountEnabled eq true and userType eq 'Member'",
        "$top": 999
    }
    stale = []
    while url:
        r = requests.get(url, headers=headers, params=params)
        r.raise_for_status()
        data = r.json()
        for u in data.get("value", []):
            last = u.get("signInActivity", {}).get("lastSignInDateTime")
            if last is None or last < cutoff:
                stale.append({"upn": u["userPrincipalName"], "lastSignIn": last or "Never"})
        url = data.get("@odata.nextLink")
        params = {}

    return sorted(stale, key=lambda x: x["lastSignIn"] or "")

stale = find_stale_users(access_token, days=90)
print(f"{len(stale)} accounts with no sign-in in 90+ days:")
for u in stale[:20]:
    print(f"  {u['upn']:<50} last: {u['lastSignIn'][:10] if u['lastSignIn'] != 'Never' else 'Never'}")

